# OOP Best Practices: Single Responsibility, Composition, Template Method

from abc import ABC, abstractmethod
from typing import List, Tuple
from dataclasses import dataclass

# Data class for match information (follows composition, not inheritance)
@dataclass
class InningsData:
    """Encapsulates innings-specific data."""
    runs: int = 0
    wickets: int = 0
    overs: float = 0.0
    boundaries: int = 0


# Best Practice 1: Single Responsibility - Statistics Manager
class PlayerStatistics:
    """Handles only player statistics - one responsibility."""

    def __init__(self, player_name: str):
        self.player_name = player_name
        self.innings_list: List[InningsData] = []

    def add_innings(self, innings: InningsData) -> None:
        """Record an innings."""
        self.innings_list.append(innings)

    def calculate_average(self) -> float:
        """Calculate average runs across innings."""
        if not self.innings_list:
            return 0.0
        total_runs = sum(i.runs for i in self.innings_list)
        return total_runs / len(self.innings_list)

    def get_summary(self) -> dict:
        """Get statistical summary."""
        return {
            "player": self.player_name,
            "innings_played": len(self.innings_list),
            "total_runs": sum(i.runs for i in self.innings_list),
            "average": self.calculate_average()
        }


# Best Practice 2: Dependency Inversion - Abstract Strategies
class ScoringStrategy(ABC):
    """Abstract base for different scoring approaches."""

    @abstractmethod
    def calculate_score(self, innings: InningsData) -> int:
        """Calculate performance score based on innings data."""
        pass


class AggressiveScoringStrategy(ScoringStrategy):
    """Aggressive batsmen score more for boundaries."""

    def calculate_score(self, innings: InningsData) -> int:
        # More weight on boundaries in aggressive play
        return innings.runs + (innings.boundaries * 5)


class ConservativeScoringStrategy(ScoringStrategy):
    """Conservative batsmen score more for not getting out."""

    def calculate_score(self, innings: InningsData) -> int:
        # Penalize getting out, reward staying at crease
        penalty = 50 if innings.wickets > 0 else 0
        return innings.runs - penalty


# Best Practice 3: Composition Over Inheritance
class BatsmanProfile:
    """A batsman profile - uses composition, not inheritance."""

    def __init__(self, name: str, style: str):
        self.name = name
        self.style = style
        # Composition: contains a statistics object, not inherits from it
        self._statistics = PlayerStatistics(name)
        # Composition: depends on strategy abstraction, not concrete implementation
        self._scoring_strategy: ScoringStrategy = None

    def set_scoring_strategy(self, strategy: ScoringStrategy) -> None:
        """Dependency Injection - strategy is injected, not hard-coded."""
        self._scoring_strategy = strategy

    def play_innings(self, runs: int, wickets: int, overs: float, boundaries: int) -> None:
        """Record an innings performance."""
        innings = InningsData(runs, wickets, overs, boundaries)
        self._statistics.add_innings(innings)

    def get_performance_score(self) -> int:
        """Calculate score based on current strategy (polymorphism)."""
        if not self._scoring_strategy or not self._statistics.innings_list:
            return 0
        latest_innings = self._statistics.innings_list[-1]
        return self._scoring_strategy.calculate_score(latest_innings)

    def get_career_stats(self) -> dict:
        """Get career statistics."""
        return self._statistics.get_summary()


class BowlerProfile:
    """A bowler profile - also uses composition."""

    def __init__(self, name: str, bowling_type: str):
        self.name = name
        self.bowling_type = bowling_type
        self._statistics = PlayerStatistics(name)  # Reuse statistics component
        self._wickets_career = 0

    def bowl_spell(self, overs: float, wickets: int, maiden_overs: int) -> None:
        """Record a bowling spell."""
        innings = InningsData(runs=0, wickets=wickets, overs=overs, boundaries=0)
        self._statistics.add_innings(innings)
        self._wickets_career += wickets

    def get_career_stats(self) -> dict:
        """Get career statistics."""
        stats = self._statistics.get_summary()
        stats["career_wickets"] = self._wickets_career
        return stats


# Best Practice 4: Template Method Pattern
class PerformanceAnalyzer(ABC):
    """Template method: defines analysis workflow, subclasses customize it."""

    def analyze(self, profile) -> str:
        """Template method defining the analysis process."""
        stats = self._gather_statistics(profile)
        assessment = self._evaluate(stats)
        recommendation = self._recommend(stats)
        return self._format_report(stats, assessment, recommendation)

    @abstractmethod
    def _gather_statistics(self, profile) -> dict:
        """Step 1: Gather statistics (customized by subclass)."""
        pass

    @abstractmethod
    def _evaluate(self, stats: dict) -> str:
        """Step 2: Evaluate performance (customized by subclass)."""
        pass

    @abstractmethod
    def _recommend(self, stats: dict) -> str:
        """Step 3: Make recommendations (customized by subclass)."""
        pass

    def _format_report(self, stats: dict, assessment: str, rec: str) -> str:
        """Step 4: Format report (same for all subclasses - template method)."""
        return f"Stats: {stats}\nAssessment: {assessment}\nRecommendation: {rec}"


class BatsmanAnalyzer(PerformanceAnalyzer):
    """Analyzer specialized for batsmen."""

    def _gather_statistics(self, profile: BatsmanProfile) -> dict:
        return profile.get_career_stats()

    def _evaluate(self, stats: dict) -> str:
        avg = stats.get("average", 0)
        if avg > 45:
            return "Excellent form - consistently high scoring"
        elif avg > 35:
            return "Good form - solid contributions"
        else:
            return "Needs improvement - average below expectations"

    def _recommend(self, stats: dict) -> str:
        innings = stats.get("innings_played", 0)
        if innings < 5:
            return "Accumulate more match experience"
        else:
            return "Focus on converting starts to big scores"


class BowlerAnalyzer(PerformanceAnalyzer):
    """Analyzer specialized for bowlers."""

    def _gather_statistics(self, profile: BowlerProfile) -> dict:
        return profile.get_career_stats()

    def _evaluate(self, stats: dict) -> str:
        wickets = stats.get("career_wickets", 0)
        if wickets > 150:
            return "Elite bowler - consistently taking wickets"
        elif wickets > 80:
            return "Effective bowler - regular contributions"
        else:
            return "Developing bowler - needs more experience"

    def _recommend(self, stats: dict) -> str:
        return "Focus on bowling tight lines and practicing death bowling"


# Demonstration of best practices
if __name__ == "__main__":
    print("=== BEST PRACTICE 1 & 3: Composition & Single Responsibility ===")
    rohit = BatsmanProfile("Rohit Sharma", "Aggressive")
    bumrah = BowlerProfile("Jasprit Bumrah", "FastBowl")

    # Set strategies via dependency injection
    aggressive_strategy = AggressiveScoringStrategy()
    rohit.set_scoring_strategy(aggressive_strategy)

    # Play innings
    rohit.play_innings(runs=89, wickets=0, overs=95.0, boundaries=12)
    rohit.play_innings(runs=120, wickets=0, overs=132.0, boundaries=15)

    bumrah.bowl_spell(overs=10.0, wickets=2, maiden_overs=3)
    bumrah.bowl_spell(overs=8.5, wickets=1, maiden_overs=2)

    print(f"\nRohit's Latest Performance Score: {rohit.get_performance_score()}")
    print(f"Rohit Career Stats: {rohit.get_career_stats()}")
    print(f"Bumrah Career Stats: {bumrah.get_career_stats()}")

    print("\n=== BEST PRACTICE 2: Dependency Inversion ===")
    conservative_strategy = ConservativeScoringStrategy()
    kohli = BatsmanProfile("Virat Kohli", "All-rounder")
    kohli.set_scoring_strategy(conservative_strategy)  # Different strategy
    kohli.play_innings(runs=95, wickets=0, overs=105.0, boundaries=10)
    print(f"Kohli with Conservative Strategy Score: {kohli.get_performance_score()}")
    kohli.set_scoring_strategy(aggressive_strategy)  # Swap strategy - no code change needed!
    print(f"Kohli with Aggressive Strategy Score: {kohli.get_performance_score()}")

    print("\n=== BEST PRACTICE 4: Template Method Pattern ===")
    batsman_analyzer = BatsmanAnalyzer()
    bowler_analyzer = BowlerAnalyzer()

    print("\nRohit Analysis:")
    print(batsman_analyzer.analyze(rohit))

    print("\nBumrah Analysis:")
    print(bowler_analyzer.analyze(bumrah))
